/**
 * Loads all assets to a skill,
 * including images, data, code. LocalLoader supports cache-busting
 * in the browser using dynamic query string parameters.
 * @class LocalLoader
 * @memberof jibo.loader
 * @private
 */

    /**
     * Base to append to all file requests.
     * @type {String}
     * @name jibo.loader.LocalLoader#basePath
     */

    /**
     * Prepare the URI request to be absolute. Also, applies asset pack requests.
     * @method jibo.loader.Loader#prepare
     * @param {String} uri The relative or absolute file to load.
     * @return {String} The absolute URI.
     */

    /**
     * Loads the asset file.
     * @method jibo.loader.LocalLoader#internalLoad
     * @protected
     * @param {String} uri The file to load.
     * @param {Function} callback Callback when complete.
     * @param {Object} [options] Optional load options
     */

    /**
     * Get the Node fs.readFile encoding type
     * @method jibo.loader.LocalLoader#getEncodingType
     * @private
     * @param {String} type The file type to load
     * @return {String} Encoding type for fs.readFile
     */

    /**
     * Gets a mime type by uri.
     * @method jibo.loader.LocalLoader#getImageMimeType
     * @private
     * @param {String} uri The file uri.
     * @return {String} The mime type.
     */